SELECT DISTINCT ?comm WHERE {
  ?airport wdt:P31 wd:Q22578 ;
           wdt:P131 ?comm .
  ?comm wdt:P361 wd:Q1216 .
  ?airport wdt:P2694 ?runway .
  ?runway wdt:P2048 ?runwayLength .
  ?runway wdt:P1595 ?runwayWidth .
  ?runway ps:P2048 ?lengthStmt ;
         pq:P298 wd:Q41382 .
  ?runway ps:P1595 ?widthStmt ;
         pq:P298 wd:Q41382 .
  FILTER(?runwayLength = "4992"^^xsd:float)
  FILTER(?runwayWidth = "100"^^xsd:float)
}

